# Testing principles — illustrated with plain assertions
# (pytest runs in the terminal; here we simulate the pattern)

def safe_divide(a, b):
    """Divide a by b, raising ValueError if b is zero."""
    if b == 0:
        raise ValueError("division by zero")
    return a / b

# Arrange - Act - Assert pattern
def test_normal_division():
    result = safe_divide(10, 2)   # Act
    assert result == 5.0          # Assert

def test_division_by_zero():
    try:
        safe_divide(1, 0)
        assert False, "should have raised"
    except ValueError as e:
        assert str(e) == "division by zero"

test_normal_division()
test_division_by_zero()
print("All tests passed!")

